"},{"name":"cockpit_set_nachlass_authorized","def":"CREATE OR REPLACE FUNCTION swift_v2.cockpit_set_nachlass_authorized(p_target_user_id uuid, p_authorized boolean)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'swift_v2', 'public'
AS $function$
DECLARE
    v_uid uuid := (select auth.uid());
BEGIN
    IF v_uid IS NULL THEN RAISE EXCEPTION 'not_authenticated'; END IF;
    IF NOT EXISTS (SELECT 1 FROM swift_v2.cockpit_user_profiles p
                   WHERE p.user_id = v_uid AND p.is_active AND p.role = 'admin') THEN
        RAISE EXCEPTION 'admin_required';
    END IF;
    UPDATE swift_v2.cockpit_user_profiles
       SET nachlass_authorized = p_authorized
     WHERE user_id = p_target_user_id;
    IF NOT FOUND THEN RAISE EXCEPTION 'target_profile_not_found'; END IF;
END; $function$
"},{"name":"cockpit_unwatch_nachlass","def":"CREATE OR REPLACE FUNCTION swift_v2.cockpit_unwatch_nachlass(p_detection_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'swift_v2', 'public'
AS $function$
DECLARE
    v_uid   uuid := (select auth.uid());
    v_role  text := swift_v2._cockpit_writer_role();
    v_watch uuid;
BEGIN
    DELETE FROM swift_v2.cockpit_nachlass_watchlist
    WHERE user_id = v_uid AND detection_id = p_detection_id
    RETURNING watch_id INTO v_watch;
    IF v_watch IS NOT NULL THEN
        PERFORM swift_v2._cockpit_watchlist_log(
            v_uid, v_uid, v_role, 'nachlass', v_watch, p_detection_id, 'unfollow', NULL, NULL, '{}'::jsonb);
    END IF;
END; $function$
"},{"name":"cockpit_watch_nachlass","def":"CREATE OR REPLACE FUNCTION swift_v2.cockpit_watch_nachlass(p_detection_id uuid, p_note text DEFAULT NULL::text, p_status text DEFAULT 'watching'::text, p_next_follow_up_at timestamp with time zone DEFAULT NULL::timestamp with time zone)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'swift_v2', 'public'
AS $function$
DECLARE
    v_uid    uuid := (select auth.uid());
    v_role   text := swift_v2._cockpit_writer_role();
    v_watch  uuid;
    v_status text := COALESCE(p_status, 'watching');
BEGIN
    IF v_status NOT IN ('watching','pursuing','passed') THEN RAISE EXCEPTION 'invalid_status'; END IF;
    IF NOT EXISTS (SELECT 1 FROM swift_v2.cockpit_user_profiles p
                   WHERE p.user_id = v_uid AND p.is_active AND p.nachlass_authorized) THEN
        RAISE EXCEPTION 'not_nachlass_authorized';
    END IF;
    IF NOT EXISTS (SELECT 1 FROM swift_v2.nachlass_detection_results d
                   WHERE d.detection_id = p_detection_id) THEN
        RAISE EXCEPTION 'detection_not_found';
    END IF;

    INSERT INTO swift_v2.cockpit_nachlass_watchlist (user_id, detection_id, note, status, next_follow_up_at, status_changed_at)
    VALUES (v_uid, p_detection_id, p_note, v_status, p_next_follow_up_at, now())
    ON CONFLICT (user_id, detection_id) DO NOTHING
    RETURNING watch_id INTO v_watch;

    IF v_watch IS NULL THEN
        SELECT watch_id INTO v_watch FROM swift_v2.cockpit_nachlass_watchlist
        WHERE user_id = v_uid AND detection_id = p_detection_id;
    ELSE
        PERFORM swift_v2._cockpit_watchlist_log(
            v_uid, v_uid, v_role, 'nachlass', v_watch, p_detection_id, 'follow',
            NULL, v_status, jsonb_build_object('has_note', (p_note IS NOT NULL),
                                               'next_follow_up_at', p_next_follow_up_at));
    END IF;
    RETURN v_watch;
END; $function$
"},{"name":"enqueue_nachlass_detection_jobs","def":"CREATE OR REPLACE FUNCTION swift_v2.enqueue_nachlass_detection_jobs(p_limit integer DEFAULT 200)
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'swift_v2', 'public'
AS $function$
DECLARE
  v_count integer := 0;
  v_row record;
BEGIN
  FOR v_row IN
    SELECT source_announcement_id::text AS sid
    FROM swift_v2.v_nachlass_detection_queue
    ORDER BY announcement_date DESC NULLS LAST, scraped_at DESC NULLS LAST
    LIMIT GREATEST(p_limit, 1)
  LOOP
    BEGIN
      PERFORM swift_v2.enqueue_enrichment_job(
        p_job_type   := 'nachlass_detection',
        p_entity_id  := NULL,
        p_input_hash := v_row.sid,
        p_payload    := jsonb_build_object('source_announcement_id', v_row.sid),
        p_priority   := 150
      );
      v_count := v_count + 1;
    EXCEPTION WHEN unique_violation THEN
      -- already queued; skip
      CONTINUE;
    END;
  END LOOP;
  RETURN v_count;
END;
$function$
"},{"name":"expire_nachlass_reviews_due","def":"CREATE OR REPLACE FUNCTION swift_v2.expire_nachlass_reviews_due(p_limit integer DEFAULT 500)
 RETURNS TABLE(review_id uuid, opportunity_window_end date)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'swift_v2', 'pg_temp'
AS $function$
DECLARE
  v_row record;
BEGIN
  FOR v_row IN
    SELECT r.review_id, d.opportunity_window_end
    FROM swift_v2.nachlass_opportunity_reviews r
    JOIN swift_v2.nachlass_detection_results d ON d.detection_id = r.detection_id
    WHERE r.review_status = 'pending_review'
      AND d.opportunity_window_end IS NOT NULL
      AND d.opportunity_window_end < CURRENT_DATE
    ORDER BY d.opportunity_window_end ASC
    LIMIT p_limit
    FOR UPDATE OF r SKIP LOCKED
  LOOP
    PERFORM swift_v2.fn_nachlass_review_act(
      v_row.review_id, 'expired',
      NULL, 'cron',
      'Opportunity window ended',
      NULL,
      jsonb_build_object('opportunity_window_end', v_row.opportunity_window_end)
    );
    review_id := v_row.review_id;
    opportunity_window_end := v_row.opportunity_window_end;
    RETURN NEXT;
  END LOOP;
END;
$function$
"},{"name":"fn_classify_nachlass_signals_from_text","def":"CREATE OR REPLACE FUNCTION swift_v2.fn_classify_nachlass_signals_from_text(p_text text)
 RETURNS jsonb
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
DECLARE
  v_text text := COALESCE(p_text, '');
  v_signals text[] := ARRAY[]::text[];
  v_score integer := 0;
  v_excerpt text := NULL;
  v_match text;
BEGIN
  IF length(v_text) < 20 THEN
    RETURN jsonb_build_object('score', 0, 'signals', '[]'::jsonb, 'excerpt', NULL, 'is_candidate', false);
  END IF;

  -- Strong signals: explicit Nachlass / Erblasser / Nachlassinsolvenz
  IF v_text ~* '\mnachlassinsolvenz\M' THEN
    v_signals := array_append(v_signals, 'nachlassinsolvenz');
    v_score := v_score + 50;
  END IF;
  IF v_text ~* '\mnachlassgericht\M' THEN
    v_signals := array_append(v_signals, 'nachlassgericht');
    v_score := v_score + 40;
  END IF;
  IF v_text ~* '\m(nachlass|nachlaß)\M' THEN
    v_signals := array_append(v_signals, 'nachlass_term');
    v_score := v_score + 30;
  END IF;
  IF v_text ~* '\m(erblasser|erblasserin)\M' THEN
    v_signals := array_append(v_signals, 'erblasser');
    v_score := v_score + 40;
  END IF;

  -- Medium signals: verstorben / deceased
  IF v_text ~* '\m(verstorben|verstorbene|verstorbenen|verstorbener)\M' THEN
    v_signals := array_append(v_signals, 'verstorben');
    v_score := v_score + 30;
  END IF;

  -- Weak signals (only count if accompanied by another)
  IF v_text ~* '\m(erbschaft|erbe|erben)\M' AND v_text ~* '\m(insolvenz|verfahren)\M' THEN
    v_signals := array_append(v_signals, 'erbschaft_in_insolvenz_context');
    v_score := v_score + 15;
  END IF;

  v_score := LEAST(v_score, 100);

  -- Build short excerpt around the first strong/medium signal hit.
  -- Limit to 240 chars to keep personal data minimal in our store.
  IF array_length(v_signals, 1) > 0 THEN
    v_match := (regexp_matches(v_text,
      '(.{0,120}(nachlassinsolvenz|nachlassgericht|nachlass|nachlaß|erblasser|erblasserin|verstorben|verstorbene|verstorbenen|verstorbener).{0,120})',
      'i'))[1];
    IF v_match IS NOT NULL THEN
      v_excerpt := regexp_replace(trim(v_match), '\s+', ' ', 'g');
      v_excerpt := left(v_excerpt, 240);
    END IF;
  END IF;

  RETURN jsonb_build_object(
    'score', v_score,
    'signals', to_jsonb(v_signals),
    'excerpt', v_excerpt,
    'is_candidate', v_score >= 30
  );
END;
$function$
"},{"name":"fn_cockpit_nachlass_act","def":"CREATE OR REPLACE FUNCTION swift_v2.fn_cockpit_nachlass_act(p_review_id uuid, p_to_status text, p_decision_reason text DEFAULT NULL::text, p_review_notes text DEFAULT NULL::text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'swift_v2', 'public', 'pg_temp'
AS $function$
DECLARE
  v_actor  uuid := auth.uid();
  v_role   swift_v2.cockpit_role;
  v_active boolean;
BEGIN
  IF v_actor IS NULL THEN
    RAISE EXCEPTION 'Not authenticated' USING ERRCODE = '28000';
  END IF;
  SELECT role, is_active INTO v_role, v_active
  FROM swift_v2.cockpit_user_profiles WHERE user_id = v_actor;
  IF NOT FOUND OR NOT v_active THEN
    RAISE EXCEPTION 'Inactive or unknown cockpit user' USING ERRCODE = '42501';
  END IF;
  IF v_role NOT IN ('admin','lead') THEN
    RAISE EXCEPTION 'Role % may not act on Nachlass reviews', v_role USING ERRCODE = '42501';
  END IF;
  PERFORM swift_v2.fn_nachlass_review_act(p_review_id, p_to_status, v_actor, v_role::text, p_decision_reason, p_review_notes, NULL::jsonb);
END;
$function$
"},{"name":"fn_compute_nachlass_delete_after","def":"CREATE OR REPLACE FUNCTION swift_v2.fn_compute_nachlass_delete_after(p_created_at timestamp with time zone, p_opportunity_window_end date, p_grace_days integer DEFAULT 14)
 RETURNS timestamp with time zone
 LANGUAGE sql
 IMMUTABLE
AS $function$
    SELECT LEAST(
        COALESCE(p_created_at, now()) + interval '6 months',
        CASE
            WHEN p_opportunity_window_end IS NOT NULL
            THEN (p_opportunity_window_end::timestamptz + (p_grace_days || ' days')::interval)
            ELSE 'infinity'::timestamptz
        END
    );
$function$
"},{"name":"fn_nachlass_review_act","def":"CREATE OR REPLACE FUNCTION swift_v2.fn_nachlass_review_act(p_review_id uuid, p_to_status text, p_actor uuid DEFAULT NULL::uuid, p_actor_role text DEFAULT NULL::text, p_decision_reason text DEFAULT NULL::text, p_review_notes text DEFAULT NULL::text, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS swift_v2.nachlass_opportunity_reviews
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'swift_v2', 'pg_temp'
AS $function$
DECLARE
  v_old swift_v2.nachlass_opportunity_reviews%ROWTYPE;
  v_new swift_v2.nachlass_opportunity_reviews%ROWTYPE;
BEGIN
  SELECT * INTO v_old FROM swift_v2.nachlass_opportunity_reviews
  WHERE review_id = p_review_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Nachlass review % not found', p_review_id
      USING ERRCODE = 'no_data_found';
  END IF;

  -- transition check happens in trigger, but pre-check for nicer error
  IF NOT swift_v2.fn_nachlass_review_transition_allowed(v_old.review_status, p_to_status) THEN
    RAISE EXCEPTION 'Cannot transition nachlass review % from % to %',
      p_review_id, v_old.review_status, p_to_status
      USING ERRCODE = 'check_violation';
  END IF;

  UPDATE swift_v2.nachlass_opportunity_reviews
     SET review_status = p_to_status,
         reviewed_by = COALESCE(p_actor, reviewed_by),
         decision_reason = COALESCE(p_decision_reason, decision_reason),
         review_notes = COALESCE(p_review_notes, review_notes)
   WHERE review_id = p_review_id
   RETURNING * INTO v_new;

  INSERT INTO swift_v2.nachlass_review_history
    (review_id, detection_id, from_status, to_status, actor, actor_role,
     decision_reason, review_notes, context)
  VALUES
    (v_new.review_id, v_new.detection_id, v_old.review_status, v_new.review_status,
     p_actor, p_actor_role, p_decision_reason, p_review_notes, COALESCE(p_context, '{}'::jsonb));

  RETURN v_new;
END;
$function$
"},{"name":"fn_nachlass_review_transition_allowed","def":"CREATE OR REPLACE FUNCTION swift_v2.fn_nachlass_review_transition_allowed(p_from text, p_to text)
 RETURNS boolean
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT CASE p_from
    WHEN 'pending_review' THEN p_to IN ('approved_internal','rejected','expired')
    WHEN 'approved_internal' THEN p_to IN ('published','rejected')
    WHEN 'published' THEN p_to IN ('rejected')  -- soft unpublish keeps status, sets unpublished_at
    WHEN 'rejected' THEN false
    WHEN 'expired' THEN false
    ELSE false
  END;
$function$
"},{"name":"publish_nachlass_review","def":"CREATE OR REPLACE FUNCTION swift_v2.publish_nachlass_review(p_review_id uuid, p_actor uuid DEFAULT NULL::uuid, p_actor_role text DEFAULT 'lead'::text)
