"},{"name":"record_nachlass_detection","def":"CREATE OR REPLACE FUNCTION swift_v2.record_nachlass_detection(p_source_announcement_id text, p_is_candidate boolean, p_score integer, p_signals jsonb, p_excerpt text, p_reasoning_ar text, p_provider text, p_input_hash text)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'swift_v2', 'public'
AS $function$
DECLARE
  v_id uuid;
  v_announcement_date date;
BEGIN
  -- pull announcement_date for window calc; fallback to today
  SELECT announcement_date INTO v_announcement_date
  FROM swift_v2.raw_insolvency_announcements
  WHERE id::text = p_source_announcement_id;

  INSERT INTO swift_v2.nachlass_detection_results (
    source_announcement_id,
    is_nachlass_candidate,
    deceased_estate_signal_score,
    detection_reasoning_ar,
    source_excerpt,
    opportunity_window_start,
    opportunity_window_end,
    delete_after,
    input_hash
  ) VALUES (
    p_source_announcement_id,
    COALESCE(p_is_candidate, false),
    LEAST(GREATEST(COALESCE(p_score, 0), 0), 100),
    p_reasoning_ar,
    p_excerpt,
    -- opportunity window: from announcement_date (or today) to +90 days for candidates
    CASE WHEN p_is_candidate THEN COALESCE(v_announcement_date, CURRENT_DATE) END,
    CASE WHEN p_is_candidate THEN COALESCE(v_announcement_date, CURRENT_DATE) + 90 END,
    -- delete_after: candidates kept 6 months, non-candidates 30 days (audit trail only)
    CASE WHEN p_is_candidate THEN now() + interval '6 months'
         ELSE now() + interval '30 days' END,
    COALESCE(p_input_hash, p_source_announcement_id)
  )
  ON CONFLICT (source_announcement_id, COALESCE(input_hash, '_no_hash_'::text))
  DO UPDATE SET
    is_nachlass_candidate        = EXCLUDED.is_nachlass_candidate,
    deceased_estate_signal_score = EXCLUDED.deceased_estate_signal_score,
    detection_reasoning_ar       = EXCLUDED.detection_reasoning_ar,
    source_excerpt               = EXCLUDED.source_excerpt,
    opportunity_window_start     = EXCLUDED.opportunity_window_start,
    opportunity_window_end       = EXCLUDED.opportunity_window_end,
    delete_after                 = EXCLUDED.delete_after,
    updated_at                   = now()
  RETURNING detection_id INTO v_id;

  -- Auto-open a pending review row for true candidates (idempotent).
  IF COALESCE(p_is_candidate, false) THEN
    INSERT INTO swift_v2.nachlass_opportunity_reviews (detection_id, review_status)
    VALUES (v_id, 'pending_review')
    ON CONFLICT DO NOTHING;
  END IF;

  RETURN v_id;
END;
$function$
"},{"name":"reject_nachlass_review","def":"CREATE OR REPLACE FUNCTION swift_v2.reject_nachlass_review(p_review_id uuid, p_reason text, p_actor uuid DEFAULT NULL::uuid, p_actor_role text DEFAULT 'analyst'::text, p_review_notes text DEFAULT NULL::text)
 RETURNS swift_v2.nachlass_opportunity_reviews
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'swift_v2', 'pg_temp'
AS $function$
BEGIN
  IF p_reason IS NULL OR length(btrim(p_reason)) = 0 THEN
    RAISE EXCEPTION 'rejection reason is required' USING ERRCODE='check_violation';
  END IF;
  RETURN swift_v2.fn_nachlass_review_act(
    p_review_id, 'rejected', p_actor, p_actor_role,
    p_reason, p_review_notes, '{}'::jsonb
  );
END;
$function$
