"},{"name":"tg_enforce_nachlass_review_gate","def":"CREATE OR REPLACE FUNCTION swift_v2.tg_enforce_nachlass_review_gate()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'pg_catalog', 'public'
AS $function$
BEGIN
  -- Cannot stamp published_at unless approval status is approved_internal or published
  IF NEW.published_at IS NOT NULL
     AND NEW.review_status NOT IN ('approved_internal','published') THEN
    RAISE EXCEPTION 'Cannot set published_at on nachlass_opportunity_reviews unless review_status is approved_internal or published (got %)',
      NEW.review_status
      USING ERRCODE = 'check_violation';
  END IF;

  -- If status moves to published, require reviewed_by + reviewed_at to be present
  IF NEW.review_status = 'published'
     AND (NEW.reviewed_by IS NULL OR NEW.reviewed_at IS NULL) THEN
    RAISE EXCEPTION 'Cannot mark nachlass_opportunity_reviews as published without reviewed_by and reviewed_at'
      USING ERRCODE = 'check_violation';
  END IF;

  RETURN NEW;
END;
$function$
"},{"name":"tg_nachlass_set_delete_after","def":"CREATE OR REPLACE FUNCTION swift_v2.tg_nachlass_set_delete_after()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    -- Always recompute on INSERT or when window_end changes to honor whichever cutoff is earlier
    IF TG_OP = 'INSERT' OR NEW.opportunity_window_end IS DISTINCT FROM OLD.opportunity_window_end
       OR NEW.delete_after IS NULL THEN
        NEW.delete_after := swift_v2.fn_compute_nachlass_delete_after(
            COALESCE(NEW.created_at, now()),
            NEW.opportunity_window_end
        );
    END IF;
    RETURN NEW;
END;
$function$
"},{"name":"tg_set_nachlass_delete_after","def":"CREATE OR REPLACE FUNCTION swift_v2.tg_set_nachlass_delete_after()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'pg_catalog', 'public'
AS $function$
DECLARE
  v_window_cutoff timestamptz;
  v_max_cutoff    timestamptz;
BEGIN
  v_max_cutoff := COALESCE(NEW.created_at, now()) + INTERVAL '6 months';

  IF NEW.opportunity_window_end IS NOT NULL THEN
    v_window_cutoff := (NEW.opportunity_window_end::timestamptz) + INTERVAL '30 days';
    IF NEW.delete_after IS NULL THEN
      NEW.delete_after := LEAST(v_window_cutoff, v_max_cutoff);
    END IF;
  ELSE
    IF NEW.delete_after IS NULL THEN
      NEW.delete_after := v_max_cutoff;
    END IF;
  END IF;

  RETURN NEW;
END;
$function$
"},{"name":"tg_set_natural_person_deletion_due_at","def":"CREATE OR REPLACE FUNCTION swift_v2.tg_set_natural_person_deletion_due_at()
