"},{"name":"trg_nachlass_review_state_machine","def":"CREATE OR REPLACE FUNCTION swift_v2.trg_nachlass_review_state_machine()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'swift_v2', 'pg_temp'
AS $function$
BEGIN
  -- updated_at maintenance
  NEW.updated_at := now();

  IF TG_OP = 'INSERT' THEN
    -- only allow inserts in pending_review
    IF NEW.review_status <> 'pending_review' THEN
      RAISE EXCEPTION 'New nachlass reviews must start in pending_review (got %)', NEW.review_status
        USING ERRCODE = 'check_violation';
    END IF;
    RETURN NEW;
  END IF;

  -- UPDATE: enforce legal transitions
  IF OLD.review_status IS DISTINCT FROM NEW.review_status THEN
    IF NOT swift_v2.fn_nachlass_review_transition_allowed(OLD.review_status, NEW.review_status) THEN
      RAISE EXCEPTION 'Illegal nachlass review transition: % -> %', OLD.review_status, NEW.review_status
        USING ERRCODE = 'check_violation';
    END IF;

    -- auto-stamps
    IF NEW.review_status IN ('approved_internal','rejected','expired')
       AND NEW.reviewed_at IS NULL THEN
      NEW.reviewed_at := now();
    END IF;

    IF NEW.review_status = 'published' AND NEW.published_at IS NULL THEN
      NEW.published_at := now();
    END IF;

    IF NEW.review_status = 'expired' AND NEW.expired_at IS NULL THEN
      NEW.expired_at := now();
    END IF;
  END IF;

  RETURN NEW;
END;
$function$
"},{"name":"unpublish_nachlass_review","def":"CREATE OR REPLACE FUNCTION swift_v2.unpublish_nachlass_review(p_review_id uuid, p_reason text, p_actor uuid DEFAULT NULL::uuid, p_actor_role text DEFAULT 'lead'::text)
 RETURNS swift_v2.nachlass_opportunity_reviews
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'swift_v2', 'pg_temp'
AS $function$
DECLARE
